components.css:
.ds-btn { display: inline-block; padding: 0.65rem 1.4rem; border-radius: 6px; font-size: 0.875rem; font-weight: 600; text-decoration: none; border: 1.5px solid transparent; cursor: pointer; transition: background 0.15s cubic-bezier(0.25, 1, 0.5, 1), color 0.15s, border-color 0.15s, transform 0.15s cubic-bezier(0.25, 1, 0.5, 1), box-shadow 0.15s cubic-bezier(0.25, 1, 0.5, 1); }
.ds-btn:hover { transform: translateY(-1px); }
.ds-btn:active { transform: scale(0.98); transition-duration: 0.08s; }
.ds-btn-primary { background: oklch(0.65 0.13 65); color: oklch(0.13 0.008 255); border-color: oklch(0.65 0.13 65); }
.ds-btn-primary:hover { background: oklch(0.57 0.14 65); border-color: oklch(0.57 0.14 65); box-shadow: 0 4px 12px color-mix(in srgb, oklch(0.65 0.13 65) 35%, transparent); }

.ds-pill { display: inline-flex; align-items: center; padding: 0.4rem 0.9rem; border-radius: 999px; font-size: 0.875rem; font-weight: 600; text-decoration: none; border: 1.5px solid transparent; transition: background 0.15s cubic-bezier(0.25, 1, 0.5, 1), transform 0.15s cubic-bezier(0.25, 1, 0.5, 1), border-color 0.15s; }
.ds-pill:hover { transform: translateY(-1px); }
.ds-pill:active { transform: scale(0.97); transition-duration: 0.08s; }
.ds-pill-primary { background: oklch(0.65 0.13 65); color: oklch(0.13 0.008 255); border-color: oklch(0.65 0.13 65); }
.ds-pill-primary:hover { background: oklch(0.57 0.14 65); border-color: oklch(0.57 0.14 65); }

.ds-card { background: oklch(1 0 0); border: 1px solid oklch(0.88 0.005 255); border-radius: 6px; padding: 1.75rem; box-shadow: 0 1px 4px rgba(0,0,0,.05), 0 6px 24px rgba(0,0,0,.07); transition: box-shadow 0.25s cubic-bezier(0.25, 1, 0.5, 1), transform 0.25s cubic-bezier(0.25, 1, 0.5, 1); }
.ds-card:hover { transform: translateY(-3px); box-shadow: 0 4px 24px rgba(0,0,0,.10); }
.ds-card-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 0.75rem; }
.ds-card-tag { font-size: 0.75rem; font-weight: 600; color: oklch(0.40 0.12 65); background: oklch(0.96 0.02 65); padding: 0.2rem 0.6rem; border-radius: 999px; }
.ds-card-year { font-size: 0.82rem; color: oklch(0.47 0.015 260); }
.ds-card-title { font-family: 'Barlow Condensed', system-ui, sans-serif; font-size: 1.2rem; font-weight: 700; line-height: 1.25; letter-spacing: -0.01em; margin: 0 0 0.75rem; color: oklch(0.13 0.008 255); }
.ds-card-desc { font-size: 1rem; line-height: 1.6; color: oklch(0.47 0.015 260); margin: 0 0 1.25rem; }
.ds-card-links { display: flex; flex-wrap: wrap; gap: 0.5rem; align-items: center; }

.ds-hero-win { background: oklch(0.96 0.02 65); border: 1px solid color-mix(in srgb, oklch(0.65 0.13 65) 20%, transparent); border-radius: 6px; padding: 0.75rem 1rem; display: inline-flex; flex-direction: column; gap: 0.2rem; }
.ds-hero-win-places { font-size: 0.9rem; font-weight: 700; color: oklch(0.40 0.12 65); }
.ds-hero-win-context { font-size: 0.8rem; color: oklch(0.47 0.015 260); }

.ds-nav { position: sticky; top: 0; z-index: 100; height: 60px; background: oklch(1 0 0 / 0.92); backdrop-filter: blur(8px); border-bottom: 1px solid oklch(0.88 0.005 255); transition: box-shadow 0.3s cubic-bezier(0.25, 1, 0.5, 1); }
.ds-nav.scrolled { box-shadow: 0 2px 20px rgba(0,0,0,.09); }
.ds-nav-inner { max-width: 1100px; margin: 0 auto; padding: 0 1.5rem; height: 100%; display: flex; align-items: center; gap: 2rem; }
.ds-nav-logo { font-family: 'Barlow Condensed', system-ui, sans-serif; font-weight: 700; font-size: 1.1rem; color: oklch(0.13 0.008 255); text-decoration: none; }
.ds-nav-logo:hover { color: oklch(0.13 0.008 255); text-decoration: none; }
.ds-nav-links { display: flex; list-style: none; gap: 1.5rem; margin: 0 0 0 auto; padding: 0; }
.ds-nav-links a { font-size: 0.95rem; font-weight: 500; color: oklch(0.47 0.015 260); text-decoration: none; transition: color 0.15s; }
.ds-nav-links a:hover, .ds-nav-links a.active { color: oklch(0.13 0.008 255); }
